/// Firebase configuration — generated by `flutterfire configure`.
///
/// These are CLIENT-SIDE identifiers, not secrets. The same values exist in
/// the committed android/app/google-services.json. Security is enforced by
/// Firebase Security Rules on the server, not by hiding these values.
///
/// No dependency on AppEnv or dotenv — keeps Firebase init simple and
/// avoids any circular import or load-order issues.
class DefaultFirebaseOptions {
  static FirebaseOptions get currentPlatform {
    if (Platform.isAndroid) return android;
    throw UnsupportedError(
      'DefaultFirebaseOptions have not been configured for this platform.',
    );
  }

