    apiKey: 'AIzaSyC9c-ngIOMfNVq91c2PHOLotcz7bud0fCg',
    appId: '1:612192598689:android:940f5cc4630eb337d90ee0',
    messagingSenderId: '612192598689',
    projectId: 'sheshield-bd387',
    storageBucket: 'sheshield-bd387.firebasestorage.app',
  );
}
